import{_ as e,r as t,o as p,c as i,b as n,d as s,e as o,f as l}from"./app-55c326ac.js";const c={},r=n("h1",{id:"python-异常处理-try-except",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#python-异常处理-try-except","aria-hidden":"true"},"#"),s(" Python: 异常处理 try-except")],-1),u=n("ul",null,[n("li",null,"在发生异常时，如果不采取任何措施，程序通常会立即停止运行，并显示栈跟踪---异常发生前调用的函数清单。对确定导致错误的代码有帮助")],-1),d=n("h2",{id:"引发异常",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#引发异常","aria-hidden":"true"},"#"),s(" 引发异常")],-1),k=n("li",null,[n("p",null,"如除以0抛出异常：ZeroDivisionError")],-1),v=n("li",null,[n("p",null,"语法错误异常：SyntaxError")],-1),m=n("li",null,[n("p",null,"代码任何地方都可")],-1),b=n("strong",null,"注意",-1),h={href:"http://dosc.python.org/3/library/exceptions.heml#bltin-exceptions",target:"_blank",rel:"noopener noreferrer"},y=l(`<h2 id="捕获异常" tabindex="-1"><a class="header-anchor" href="#捕获异常" aria-hidden="true">#</a> 捕获异常</h2><ul><li><p>异常发生，有两种选择;</p><ul><li>1.忽略异常，让程序崩溃并显示栈跟踪。程序开发期间，这样做，对栈跟踪提供的调试信息很有帮</li><li>2.捕获异常，并打印友好的错误信息乃至试图修复问题。对于供非程序员使用的程序，几乎都这样做</li></ul></li><li><p>使用语法：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">try</span><span class="token punctuation">:</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token keyword">except</span> Errorname<span class="token punctuation">(</span>异常名<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 捕获异常案例</span>
<span class="token keyword">def</span> <span class="token function">get_age</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">while</span> <span class="token boolean">True</span><span class="token punctuation">:</span>
        <span class="token keyword">try</span><span class="token punctuation">:</span>
            n <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token string">&quot;how old are you?&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
            <span class="token keyword">return</span> n
        <span class="token keyword">except</span> ValueError<span class="token punctuation">:</span>
            <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;Please enter an intefer value.&#39;</span><span class="token punctuation">)</span>
            
<span class="token comment"># while循环中的try/except快，可将可能引发异常的代码放在try快中</span>
<span class="token comment"># 当try快中的代码发生异常，就会跳过其他没有执行的语句，立即跳转到except快中。</span>
<span class="token comment"># 如果try快没有引发异常，将跳过 except ValueError快</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul><h2 id="try-except-块" tabindex="-1"><a class="header-anchor" href="#try-except-块" aria-hidden="true">#</a> try/except 块</h2><ul><li><p>工作原理有点类似if语句</p></li><li><p>if语句是根据布尔表达式的结果决定下面执行的内容</p></li><li><p>try/except根据是否出现了异常决定下面执行的内容</p></li><li><p>同一函数可能引发多种异常，所以就需要进行多种异常的捕获</p></li></ul><h3 id="捕获多种异常" tabindex="-1"><a class="header-anchor" href="#捕获多种异常" aria-hidden="true">#</a> 捕获多种异常</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment">## 处理多种异常的try/except快</span>
<span class="token keyword">def</span> <span class="token function">convert_init</span><span class="token punctuation">(</span>s<span class="token punctuation">,</span>base<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">try</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token builtin">int</span><span class="token punctuation">(</span>s<span class="token punctuation">,</span>base<span class="token punctuation">)</span>
    <span class="token keyword">except</span> <span class="token punctuation">(</span>ValueError<span class="token punctuation">,</span>TypeError<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token string">&#39;error&#39;</span>
    
<span class="token comment"># 分别处理不同的异常</span>

<span class="token keyword">def</span> <span class="token function">convert_ini2</span><span class="token punctuation">(</span>s<span class="token punctuation">,</span>base<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">try</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token builtin">int</span><span class="token punctuation">(</span>s<span class="token punctuation">.</span>base<span class="token punctuation">)</span>
    <span class="token keyword">except</span> ValueError<span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token string">&quot;value error&quot;</span>
    <span class="token keyword">except</span> TypeError<span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token string">&quot;type error&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="捕获所有异常" tabindex="-1"><a class="header-anchor" href="#捕获所有异常" aria-hidden="true">#</a> 捕获所有异常</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 在except中没有指定异常，将捕获所有异常</span>
<span class="token keyword">def</span> <span class="token function">convert_to_init</span><span class="token punctuation">(</span>s<span class="token punctuation">,</span>base<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">try</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token builtin">int</span><span class="token punctuation">(</span>s<span class="token punctuation">,</span>base<span class="token punctuation">)</span>
    <span class="token keyword">except</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token string">&#39;error&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="清理操作" tabindex="-1"><a class="header-anchor" href="#清理操作" aria-hidden="true">#</a> 清理操作</h2><ul><li>在try/except 块中，可以包含 执行清理操作的finally代码块</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 清理操作案例（或者说语法）</span>
<span class="token keyword">def</span> <span class="token function">invert</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">try</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token number">1</span><span class="token operator">/</span>x
    <span class="token keyword">except</span> ZeroDivisionError<span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token string">&#39;error&#39;</span>
    <span class="token keyword">finally</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;invert(%s) done&#39;</span> <span class="token operator">%</span> x<span class="token punctuation">)</span>
        
<span class="token comment"># finally块肯定会执行，不管是否发生异常都要执行某些代码块时，很有用处</span>
<span class="token comment"># 如通常将关闭文件的语句放在finally块中，这样文件肯定会被关闭，即使发生了IOError</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="另一种格式设置方法" tabindex="-1"><a class="header-anchor" href="#另一种格式设置方法" aria-hidden="true">#</a> 另一种格式设置方法</h2><ul><li>在上述的代码块中，为让文件每行开头的行号右对齐，并在行号的左边填充零。</li><li>print语句都使用了字符串插入</li><li>当需要使用格式字符串，可将print语句替换成下面的语句:<code>print(&#39;{0:04}{1}&#39;.format(num,line),end = &#39;&#39;)</code></li></ul><h2 id="with语句" tabindex="-1"><a class="header-anchor" href="#with语句" aria-hidden="true">#</a> with语句</h2><ul><li><p>为了确保发生异常，也能尽快执行清理操作。可以使用python语句with</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 在屏幕上打印文件内容，并在每一行加上行号</span>
num <span class="token operator">=</span> <span class="token number">1</span>
f <span class="token operator">=</span> <span class="token builtin">open</span><span class="token punctuation">(</span>fname<span class="token punctuation">)</span>
<span class="token keyword">for</span> line <span class="token keyword">in</span> f<span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;{0:04}{1}&#39;</span><span class="token punctuation">.</span><span class="token builtin">format</span><span class="token punctuation">(</span>num<span class="token punctuation">,</span>line<span class="token punctuation">)</span><span class="token punctuation">,</span>end <span class="token operator">=</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">)</span>
    num <span class="token operator">=</span> num <span class="token operator">+</span> <span class="token number">1</span>
f<span class="token punctuation">.</span>close<span class="token punctuation">(</span><span class="token punctuation">)</span>

<span class="token comment"># 由于不知道文件将在何时关闭，f通常在for循环结束后关闭，但不清楚去确切的时间。</span>
<span class="token comment"># 当不知需要后，f 保持打开状态时不确定的，当其他程序访问这个文件，就会导致出错</span>

<span class="token comment"># 改进，使用with语句</span>
<span class="token comment"># 确保不在需要的文件尽早关闭 可使用with语句</span>
num <span class="token operator">=</span> <span class="token number">1</span>
<span class="token keyword">with</span> <span class="token builtin">open</span><span class="token punctuation">(</span>fname<span class="token punctuation">,</span><span class="token string">&#39;r&#39;</span><span class="token punctuation">)</span> <span class="token keyword">as</span> f<span class="token punctuation">:</span>
    <span class="token keyword">for</span> line <span class="token keyword">in</span> f<span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;{0:04}{1}&#39;</span><span class="token punctuation">.</span><span class="token builtin">format</span><span class="token punctuation">(</span>num<span class="token punctuation">,</span>line<span class="token punctuation">)</span><span class="token punctuation">,</span>end <span class="token operator">=</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">)</span>
        num <span class="token operator">=</span> num <span class="token operator">+</span> <span class="token number">1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul>`,15);function f(x,w){const a=t("ExternalLinkIcon");return p(),i("div",null,[r,u,d,n("ul",null,[k,v,m,n("li",null,[n("p",null,[b,s(" 大量内置的异常，被组织成层次结构，可参阅："),n("a",h,[s("http://dosc.python.org/3/library/exceptions.heml#bltin-exceptions"),o(a)])])])]),y])}const _=e(c,[["render",f],["__file","try-except.html.vue"]]);export{_ as default};
